package keeper

import (
	"encoding/hex"
	"fmt"
	"math/big"
	"strings"

	"github.com/ethereum/go-ethereum/common"
)

// V7ContractVersion tags the deployed contract so EnsureContractsDeployed can
// detect a bytecode upgrade and force-redeploy the new version automatically.
const V7ContractVersion = "v7.8-escrow-lastdemurrage-reset"

// V7ContractBytecode is the compiled bytecode of AequitasV7.sol (solc 0.8.35, optimizer 200 runs).
// v7.2-mandatory-nullifier: nullifier is now required (not optional) in both register() and
// registerWithSig(); nullifier is included in the signed message hash to prevent relayer substitution.
// v7.6-v2-only-nullifier: register()/registerWithSig() now REQUIRE pubSignals[1] != 0
// (the ZK-circuit-bound nullifier) — the old fallback that trusted a caller-supplied
// nullifier whenever a v1-circuit proof omitted it (pubSignals[1] == 0) is removed,
// since that fallback had zero cryptographic binding to the proof and let anyone pick
// an arbitrary nullifier, defeating "one biometric = one registration". Also adds an
// explicit claimedHuman != address(0) check in registerWithSig (ecrecover can return
// address(0) on malformed signatures) and fixes triggerEscrowToUBI to actually release
// the swept human's guardian wardCount slot, which a stale comment claimed was already
// handled but never was.
// v7.7-confirmguardian-ishuman: confirmGuardian() now requires isHuman[msg.sender],
// matching revokeGuardian. Without this, a human de-registered via triggerEscrowToUBI
// while a guardian proposal was still pending could call confirmGuardian() afterward
// and permanently consume a wardCount slot that could then never be released by any
// path (revokeGuardian and triggerEscrowToUBI both require isHuman==true to release one).
// v7.8-escrow-lastdemurrage-reset: _confirmAlive() now resets lastDemurrage on
// escrow release. Without this, the next _applyDemurrage call computed elapsed
// time over the ENTIRE inactivity + escrow span (often years), and the
// resulting fee is capped at 100% of the excess-over-fairShare() — so a
// recovering human's wake-up bonus + returned escrow was taxed straight back
// down to fairShare() almost immediately.
// Compiled from AequitasV7.sol on 2026-06-27.
const V7ContractBytecode = ""

// BioVerifierRuntimeBytecode is the deployed runtime bytecode of BioVerifierV3.sol
// (Poseidon-based nullifier circuit, solc 0.8.35).
// IMPORTANT: this constant must match the bytecode deployed on-chain. EnsureContractsDeployed
// overwrites the DB entry if they diverge — so updating the contract without updating this
// constant destroys the deployment on the next restart.
const BioVerifierRuntimeBytecode = ""

// EnsureContractsDeployed checks if V7 and BioVerifier contracts exist in the DB.
// If not, it redeploys them from hardcoded bytecode. Called at node startup so
// a DB reset never leaves the node in a broken "no code at address" state.
func EnsureContractsDeployed(evm *EVMEngine, state *ChainState, deployerAddr string) {
	// Check BioVerifier contract first. V7 registerWithSig calls this address;
	// without code there, proof verification reverts even when V7 itself exists.
	bioAddr := strings.ToLower(BIO_VERIFIER_ADDR)
	existingBio, err := state.LoadContract(bioAddr)
	expectedBio, decErr := hex.DecodeString(BioVerifierRuntimeBytecode)
	bioNeedsUpdate := err != nil || len(existingBio) == 0 ||
		(decErr == nil && hex.EncodeToString(existingBio) != BioVerifierRuntimeBytecode)
	if bioNeedsUpdate {
		if decErr != nil {
			fmt.Printf("[DEPLOY] ERROR: failed to decode BioVerifier bytecode: %v\n", decErr)
		} else if saveErr := state.SaveContract(bioAddr, expectedBio, deployerAddr); saveErr != nil {
			fmt.Printf("[DEPLOY] ERROR: failed to save BioVerifier bytecode: %v\n", saveErr)
		} else {
			fmt.Printf("[DEPLOY] BioVerifier deployed/updated at %s (%d bytes)\n", BIO_VERIFIER_ADDR, len(expectedBio))
		}
	} else {
		fmt.Printf("[DEPLOY] BioVerifier already deployed at %s (%d bytes)\n", BIO_VERIFIER_ADDR, len(existingBio))
	}

	// Check V7 contract — redeploy if missing or version changed.
	v7Addr := strings.ToLower(V7_CONTRACT_ADDR)
	existing, err := state.LoadContract(v7Addr)
	// restoreOnFailure is set only on upgrade paths; nil on fresh deploy.
	var restoreOnFailure func(string)
	if err == nil && len(existing) > 0 {
		// FIX (audit 2026-06-28 recheck 4, P0-1): startup deploy code, no
		// cs.mu held — must use the plain DB-only read.
		storedVersion := state.getConfigValueDB("v7_contract_version")
		if storedVersion == V7ContractVersion {
			fmt.Printf("[DEPLOY] V7 contract already deployed at %s (%d bytes)\n", V7_CONTRACT_ADDR, len(existing))
			return
		}
		fmt.Printf("[DEPLOY] V7 contract version changed (%q → %q) — redeploying with new bytecode...\n",
			storedVersion, V7ContractVersion)
		// Before wiping EVM storage: save relationship slots AND the critical
		// ubiPerHumanAccumulated (slot 3) which is NOT in Go-state. After the
		// wipe, slot 3 is empty, so MigrateEVMFromGoState would read 0 and set
		// ubiClaimed=0 for everyone (allowing double-claiming). We save slot 3
		// here and restore it AFTER migration in evm_storage.go.
		ubiSlot2Key := common.BigToHash(big.NewInt(2)).Hex()
		ubiSlot2Val, _ := state.LoadStorageSlot(v7Addr, ubiSlot2Key)
		if ubiSlot2Val != "" {
			fmt.Printf("[DEPLOY] Saving ubiPool (slot 2) before wipe\n")
		}
		ubiSlot3Key := common.BigToHash(big.NewInt(3)).Hex()
		ubiSlot3Val, _ := state.LoadStorageSlot(v7Addr, ubiSlot3Key)
		if ubiSlot3Val != "" {
			fmt.Printf("[DEPLOY] Saving ubiPerHumanAccumulated (slot 3) = %s before wipe\n", ubiSlot3Val[:min(16, len(ubiSlot3Val))])
		}
		// Back up all storage slots before the destructive wipe so we can
		// restore them if deployment fails and avoid leaving an empty V7 state.
		oldCode := existing
		oldSlots, backupErr := state.LoadAllStorageSlots(v7Addr)
		if backupErr != nil {
			fmt.Printf("[DEPLOY] WARNING: could not backup storage before upgrade: %v\n", backupErr)
			oldSlots = nil
		}
		restoreOnFailure = func(reason string) {
			fmt.Printf("[DEPLOY] ERROR: %s — restoring previous V7 state\n", reason)
			if len(oldCode) > 0 {
				state.SaveContract(v7Addr, oldCode, deployerAddr)
			}
			for slot, val := range oldSlots {
				state.SaveStorageSlot(v7Addr, slot, val)
			}
		}

		// FIX: abort the upgrade if the relationship-slot snapshot fails —
		// proceeding to wipe evm_storage afterward would permanently lose
		// guardian/escrow relationships (slots 5, 13-16) with no way to
		// recover them, since they aren't tracked in any Go-state table.
		if snapErr := state.SavePreUpgradeRelationshipSlots(v7Addr); snapErr != nil {
			if restoreOnFailure != nil {
				restoreOnFailure("could not snapshot guardian/escrow relationship slots: " + snapErr.Error())
			} else {
				fmt.Printf("[DEPLOY] ERROR: could not snapshot guardian/escrow relationship slots: %v\n", snapErr)
			}
			return
		}

		// FIX 12: Wrap the destructive wipe in a DB transaction so a crash
		// mid-upgrade does not leave evm_contracts/evm_storage in a half-deleted state.
		upgradeTx, txErr := state.db.Begin()
		if txErr != nil {
			if restoreOnFailure != nil {
				restoreOnFailure("could not begin upgrade transaction: " + txErr.Error())
			} else {
				fmt.Printf("[DEPLOY] ERROR: could not begin upgrade transaction: %v\n", txErr)
			}
			return
		}
		// FIX: this deleted from a column named "contract_address", which does
		// not exist on evm_storage (the actual column is "address" — see
		// state.go's CREATE TABLE). Every upgrade's storage wipe therefore
		// silently failed (error was discarded via the old //nolint:errcheck),
		// leaving the OLD contract's storage slots (isHuman, balanceOf,
		// usedCommitments, nullifier slots, etc.) in the DB under the same
		// address the new contract reuses — exactly the kind of stale state
		// that resurfaces as "already registered" after a reset/redeploy.
		if _, delErr := upgradeTx.Exec(`DELETE FROM evm_contracts WHERE lower(address) = $1`, v7Addr); delErr != nil {
			upgradeTx.Rollback() //nolint:errcheck
			if restoreOnFailure != nil {
				restoreOnFailure("could not delete stale evm_contracts row: " + delErr.Error())
			} else {
				fmt.Printf("[DEPLOY] ERROR: could not delete stale evm_contracts row: %v\n", delErr)
			}
			return
		}
		if _, delErr := upgradeTx.Exec(`DELETE FROM evm_storage WHERE lower(address) = $1`, v7Addr); delErr != nil {
			upgradeTx.Rollback() //nolint:errcheck
			if restoreOnFailure != nil {
				restoreOnFailure("could not delete stale evm_storage rows: " + delErr.Error())
			} else {
				fmt.Printf("[DEPLOY] ERROR: could not delete stale evm_storage rows: %v\n", delErr)
			}
			return
		}
		if commitErr := upgradeTx.Commit(); commitErr != nil {
			upgradeTx.Rollback() //nolint:errcheck
			if restoreOnFailure != nil {
				restoreOnFailure("upgrade wipe commit failed: " + commitErr.Error())
			} else {
				fmt.Printf("[DEPLOY] ERROR: upgrade wipe commit failed: %v\n", commitErr)
			}
			return
		}

		// Restore slot 2 (ubiPool) and slot 3 (ubiPerHumanAccumulated) immediately
		// after wipe so MigrateEVMFromGoState can read them. Without slot 2 restore,
		// the ubiPool balance in V7 is zeroed after every upgrade.
		if ubiSlot2Val != "" {
			state.SaveStorageSlot(v7Addr, ubiSlot2Key, ubiSlot2Val)
		}
		if ubiSlot3Val != "" {
			state.SaveStorageSlot(v7Addr, ubiSlot3Key, ubiSlot3Val)
		}
	} else {
		fmt.Printf("[DEPLOY] V7 contract not found — deploying from hardcoded bytecode...\n")
	}

	bytecode, err := hex.DecodeString(V7ContractBytecode)
	if err != nil {
		if restoreOnFailure != nil {
			restoreOnFailure("failed to decode V7 bytecode: " + err.Error())
		} else {
			fmt.Printf("[DEPLOY] ERROR: failed to decode V7 bytecode: %v\n", err)
		}
		return
	}

	// ABI-encode constructor argument: BIO_VERIFIER_ADDR (address)
	bioVerifierAddr := common.HexToAddress(BIO_VERIFIER_ADDR)
	// Constructor arg: 32 bytes, left-padded address
	constructorArg := make([]byte, 32)
	copy(constructorArg[12:], bioVerifierAddr.Bytes())
	deployBytecode := append(bytecode, constructorArg...)

	deployer := common.HexToAddress(deployerAddr)
	contractAddr, _, err := evm.DeployContract(deployer, deployBytecode, big.NewInt(0))
	if err != nil {
		if restoreOnFailure != nil {
			restoreOnFailure("failed to deploy V7 contract: " + err.Error())
		} else {
			fmt.Printf("[DEPLOY] ERROR: failed to deploy V7 contract: %v\n", err)
		}
		return
	}

	deployedAddr := strings.ToLower(contractAddr.Hex())
	if deployedAddr != v7Addr {
		fmt.Printf("[DEPLOY] WARNING: deployed at %s but expected %s\n", deployedAddr, v7Addr)
		fmt.Printf("[DEPLOY] Saving runtime code under expected address %s\n", v7Addr)
		// Save under the expected address so existing code references work.
		runtimeCode, _ := state.LoadContract(deployedAddr)
		if len(runtimeCode) > 0 {
			state.SaveContract(v7Addr, runtimeCode, deployerAddr)
		}
		// FIX 7: Remove the stale DB entries at the EVM-assigned address so the
		// database doesn't hold orphaned rows that waste space and could confuse
		// future contract lookups. The canonical copy is now at v7Addr above.
		if state.db != nil {
			// FIX: was deleting from non-existent column "contract_address"
			// (evm_storage's actual column is "address") — silently failed,
			// leaving orphaned rows at deployedAddr forever. Now checks errors
			// and reports actual outcome instead of an unconditional success print.
			_, cErr := state.db.Exec(`DELETE FROM evm_contracts WHERE lower(address) = $1`, deployedAddr)
			_, sErr := state.db.Exec(`DELETE FROM evm_storage WHERE lower(address) = $1`, deployedAddr)
			if cErr != nil || sErr != nil {
				fmt.Printf("[DEPLOY] WARNING: failed to remove stale entries at %s (contracts: %v, storage: %v)\n", deployedAddr, cErr, sErr)
			} else {
				fmt.Printf("[DEPLOY] Removed stale evm_contracts/evm_storage entries at %s\n", deployedAddr)
			}
		}
	} else {
		fmt.Printf("[DEPLOY] ✓ V7 contract deployed at %s\n", V7_CONTRACT_ADDR)
	}
	// Repopulate EVM storage from Go-state BEFORE setting the version marker.
	// FIX 13: Only mark the upgrade complete if migration succeeds — a failed
	// migration that sets the version marker would permanently skip re-migration.
	if err := state.MigrateEVMFromGoState(V7_CONTRACT_ADDR); err != nil {
		if restoreOnFailure != nil {
			restoreOnFailure("migration failed, not marking upgrade complete: " + err.Error())
		} else {
			fmt.Printf("[DEPLOY] ERROR: migration failed, not marking upgrade complete: %v\n", err)
		}
		return
	}
	// FIX (audit 2026-06-28 recheck 4, P0-1): same as above — plain DB-only write.
	state.setConfigValueDB("v7_contract_version", V7ContractVersion)
}
